import base64, io
from PIL import Image
import numpy as np
from pathlib import Path

IMG_B64 = """"""


src = Image.open(io.BytesIO(base64.b64decode(IMG_B64))).convert("RGBA")
arr = np.array(src)
gold = (212, 175, 55)
out = np.zeros_like(arr)
out[:,:,0] = gold[0]
out[:,:,1] = gold[1]
out[:,:,2] = gold[2]
out[:,:,3] = arr[:,:,3]
result = Image.fromarray(out, "RGBA")

static = Path("static")
for name, size in [("favicon-16x16.png",16),("favicon-32x32.png",32),("apple-touch-icon.png",180),("logo-512.png",512)]:
    result.resize((size,size), Image.LANCZOS).save(static/name)
    print(f"✅ {name}")

imgs = [result.resize((s,s), Image.LANCZOS) for s in [16,32,48]]
imgs[0].save(static/"favicon.ico", format="ICO", sizes=[(16,16),(32,32),(48,48)], append_images=imgs[1:])
print("✅ favicon.ico")
